#nullable enable // autogenerated

using PVZEngine;

namespace MVZ2Logic.HeldItems
{
    public static class LogicHeldItemNames
    {
        public const string none = "none";
        public const string blueprint = "blueprint";
        public const string conveyor = "conveyor";
        public const string pickaxe = "pickaxe";
        public const string starshard = "starshard";
        public const string trigger = "trigger";
        public const string sword = "sword";
    }
    public static class LogicHeldTypes
    {
        public static readonly NamespaceID pickaxe = Get(LogicHeldItemNames.pickaxe);
        public static readonly NamespaceID starshard = Get(LogicHeldItemNames.starshard);
        public static readonly NamespaceID trigger = Get(LogicHeldItemNames.trigger);
        public static readonly NamespaceID sword = Get(LogicHeldItemNames.sword);
        public static readonly NamespaceID none = Get(LogicHeldItemNames.none);
        public static readonly NamespaceID blueprint = Get(LogicHeldItemNames.blueprint);
        public static readonly NamespaceID conveyor = Get(LogicHeldItemNames.conveyor);
        public static NamespaceID Get(string name)
        {
            return new NamespaceID(Global.BuiltinNamespace, name);
        }
    }
}
